import redis from './redis';

const STREAM = 'events:orders';
const GROUP = 'order-processors';
const CONSUMER = `consumer-${process.pid}`;

export async function initStream() {
  try {
    await redis.xgroup('CREATE', STREAM, GROUP, '0', 'MKSTREAM');
  } catch { /* group may already exist */ }
}

export async function publishEvent(data: Record<string, string>) {
  await redis.xadd(STREAM, 'MAXLEN', '~', '10000', '*', ...Object.entries(data).flat());
}

export async function consumeEvents() {
  const results = await redis.xreadgroup('GROUP', GROUP, CONSUMER, 'COUNT', 10, 'BLOCK', 5000, 'STREAMS', STREAM, '>');
  if (results) {
    for (const [, messages] of results) {
      for (const [id, fields] of messages) {
        console.log('Processing:', id, fields);
        await redis.xack(STREAM, GROUP, id);
      }
    }
  }
}

