import { exec } from 'child_process';
import { promisify } from 'util';

const execAsync = promisify(exec);

export async function backupPostgres(): Promise<string> {
  const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
  const filename = `backup-${timestamp}.sql.gz`;
  await execAsync(
    `pg_dump "${process.env.DATABASE_URL}" | gzip > /backups/${filename}`
  );
  return filename;
}

export async function backupRedis(): Promise<void> {
  await execAsync('redis-cli BGSAVE');
}

export async function backupMongoDB(): Promise<string> {
  const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
  const dir = `/backups/mongo-${timestamp}`;
  await execAsync(`mongodump --uri="${process.env.MONGODB_URI}" --out=${dir} --gzip`);
  return dir;
}

